// Parse GitHub push event
const body = $input.first().json;
const repo = body.repository?.name || body.repo || 'unknown';
const branch = (body.ref || '').replace('refs/heads/', '');
const pusher = body.pusher?.name || body.sender?.login || 'unknown';
const commits = body.commits || [];
const commitCount = commits.length;
const lastMsg = commits[commits.length - 1]?.message || 'no message';

// Only deploy from main branch
const shouldDeploy = branch === 'main';

// Map repo to deploy action
const DEPLOY_MAP = {
  'noizy-heaven': { action: 'deploy_heaven', cmd: 'cd /Users/m2ultra/Desktop/HEAVEN && npx wrangler deploy' },
  'noizy-gabriel': { action: 'restart_gabriel', cmd: 'cd /Users/m2ultra/NOIZYLAB && bun run repos/noizy-gabriel/src/daemon.ts' },
  'noizy-supersonic': { action: 'rebuild_supersonic', cmd: 'cd /Users/m2ultra/NOIZYLAB/supersonic && source venv/bin/activate && pip install -e .' },
  'noizy-infra': { action: 'sync_infra', cmd: 'echo "Infra updated — manual review required"' },
};

const deployConfig = DEPLOY_MAP[repo] || { action: 'log_only', cmd: 'echo "No auto-deploy for ' + repo + '"' };

return [{
  json: {
    repo,
    branch,
    pusher,
    commit_count: commitCount,
    last_message: lastMsg,
    should_deploy: shouldDeploy,
    ...deployConfig,
    timestamp: new Date().toISOString(),
    pipeline: 'GITHUB_DEPLOY'
  }
}];
